import pandas as pdstudents= pd.read_csv('students.csv')print('----2----')print(students.head(5))print(students.shape)print(students.dtypes)print('----2----')print('----3----')print(students.query('math > 80'))print(students.query('attendance < 70'))print('----3----')print('----4----')print(students.query('math >75 and physics > 75 and cs >75'))print('----4----')print('second')students['average_grade'] = (students['math'] + students['physics'] + students['cs']) / 3students['status'] = students['average_grade'].apply(lambda x: 'pass' if x >= 75 else 'fail')students.sort_values(by='average_grade', ascending=False, inplace=True)print(students.head(3))class StudentAnalytics:    def __init__(self, df):        self.df = df    def top_students(self, n):        return students.sort_values(by='average_grade', ascending=False).head(n)    def group_average(self):        return students.aggregate({'math': 'mean', 'physics': 'mean', 'cs': 'mean'})    def low_attendance(self, threshold):        return students.query('attendance < @threshold')    def summary(self):        print("Student count: ", len(self.df))        print("Average grades: ", self.df['average_grade'].mean())        print('Average attendance: ', self.df['attendance'].mean())analytics = StudentAnalytics(students)print(analytics.top_students(3))print(analytics.group_average())print(analytics.low_attendance(70))analytics.summary()